import { useEffect, useState } from "react";

const App = () => {
  const [questions, setQuestions] = useState([]);
  const [selected, setSelected] = useState({});
  const [currentPage, setCurrentPage] = useState(0);

  useEffect(() => {
    // Mocking fetch - two questions will show per "page"
    setQuestions([
      { id: 1, question: "What is the primary use of a mmWave Radar sensor?", options: ["Humidity", "Presence", "Soil pH", "Wind Speed"] },
      { id: 2, question: "Which protocol is commonly used for Digital Light Sensors?", options: ["I2C", "SATA", "MIDI", "POP3"] },
      { id: 3, question: "What does an LDR measure?", options: ["Moisture", "Light", "Gas", "Pressure"] },
      { id: 4, question: "Which sensor measures decibel levels?", options: ["DHT11", "SPL Meter", "MQ-135", "BMP280"] }
    ]);
  }, []);

  const handleSelect = (qid, opt) => {
    setSelected((prev) => ({ ...prev, [qid]: opt }));
  };

  // Logic to get 2 questions for the current page
  const questionsPerPage = 2;
  const startIndex = currentPage * questionsPerPage;
  const currentBatch = questions.slice(startIndex, startIndex + questionsPerPage);
  const totalPages = Math.ceil(questions.length / questionsPerPage);

  if (questions.length === 0) return <div style={styles.container}>Loading...</div>;

  return (
    <div style={styles.container}>
      <div style={styles.blob1}></div>
      <div style={styles.blob2}></div>

      <div style={styles.wrapper}>
        {/* HEADER - Slimmer version */}
        <header style={styles.header}>
          <h1 style={styles.title}>Quizzly <span style={styles.versionTag}>v1</span></h1>
          <div style={styles.userInfo}>
            <span style={styles.userName}>Harshith B • 23MIS0012</span>
            <span style={styles.counter}>Page {currentPage + 1} of {totalPages}</span>
          </div>
        </header>

        {/* QUESTIONS CONTAINER - This takes up the remaining height */}
        <main style={styles.main}>
          {currentBatch.map((q) => (
            <div key={q.id} style={styles.questionCard}>
              <div style={styles.cardHeader}>
                <span style={styles.badge}>Question {q.id}</span>
                <h2 style={styles.questionText}>{q.question}</h2>
              </div>

              <div style={styles.optionsGrid}>
                {q.options.map((opt) => {
                  const isSelected = selected[q.id] === opt;
                  return (
                    <button
                      key={opt}
                      onClick={() => handleSelect(q.id, opt)}
                      style={{
                        ...styles.optionBtn,
                        ...(isSelected ? styles.optionSelected : {}),
                      }}
                    >
                      <div style={{
                        ...styles.radio,
                        borderColor: isSelected ? "#6366f1" : "rgba(255,255,255,0.2)"
                      }}>
                        {isSelected && <div style={styles.radioInner}></div>}
                      </div>
                      {opt}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}
        </main>

        {/* FOOTER - Pinned to bottom */}
        <footer style={styles.footer}>
          <button 
            disabled={currentPage === 0}
            onClick={() => setCurrentPage(v => v - 1)}
            style={{...styles.navBtn, opacity: currentPage === 0 ? 0.3 : 1}}
          >
            Previous
          </button>

          <button 
            onClick={() => {
              if (currentPage < totalPages - 1) {
                setCurrentPage(v => v + 1);
              } else {
                alert("Final Submission Successful");
              }
            }}
            style={styles.nextBtn}
          >
            {currentPage === totalPages - 1 ? "Submit Exam" : "Save & Next"}
          </button>
        </footer>
      </div>
    </div>
  );
};

const styles = {
  container: {
    height: "100vh",
    width: "100vw",
    backgroundColor: "#0b0f1a",
    color: "#f8fafc",
    fontFamily: "'Inter', sans-serif",
    display: "flex",
    justifyContent: "center",
    overflow: "hidden",
    position: "relative",
  },
  wrapper: {
    width: "100%",
    maxWidth: "950px",
    display: "flex",
    flexDirection: "column",
    padding: "20px",
    zIndex: 10,
  },
  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "15px",
  },
  title: { fontSize: "20px", fontWeight: "800", margin: 0 },
  versionTag: { fontSize: "10px", color: "#6366f1", border: "1px solid #6366f1", padding: "2px 6px", borderRadius: "4px" },
  userInfo: { textAlign: "right", display: "flex", flexDirection: "column" },
  userName: { fontSize: "12px", color: "#94a3b8" },
  counter: { fontSize: "12px", fontWeight: "700", color: "#6366f1" },

  main: {
    flex: 1, // Fills the middle space
    display: "flex",
    flexDirection: "column",
    gap: "15px",
    justifyContent: "center"
  },
  questionCard: {
    background: "rgba(30, 41, 59, 0.4)",
    backdropFilter: "blur(12px)",
    borderRadius: "20px",
    padding: "20px 30px",
    border: "1px solid rgba(255, 255, 255, 0.08)",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    flex: 1, // Cards share height equally
    maxHeight: "40vh", // Prevents cards from getting too tall
  },
  badge: { fontSize: "10px", color: "#818cf8", fontWeight: "700", textTransform: "uppercase", marginBottom: "8px" },
  questionText: { fontSize: "18px", margin: "0 0 15px 0", fontWeight: "600", color: "#f1f5f9" },

  optionsGrid: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "12px",
  },
  optionBtn: {
    all: "unset",
    display: "flex",
    alignItems: "center",
    padding: "12px 20px",
    background: "rgba(255,255,255,0.03)",
    border: "1px solid rgba(255,255,255,0.06)",
    borderRadius: "12px",
    cursor: "pointer",
    fontSize: "14px",
    transition: "0.2s",
  },
  optionSelected: { background: "rgba(99, 102, 241, 0.15)", borderColor: "#6366f1" },
  radio: { width: "14px", height: "14px", border: "2px solid", borderRadius: "50%", marginRight: "12px", display: "flex", alignItems: "center", justifyContent: "center" },
  radioInner: { width: "6px", height: "6px", background: "#6366f1", borderRadius: "50%" },

  footer: {
    marginTop: "15px",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
  },
  navBtn: { all: "unset", color: "#94a3b8", fontWeight: "600", cursor: "pointer", fontSize: "14px" },
  nextBtn: { all: "unset", background: "#6366f1", padding: "10px 28px", borderRadius: "10px", fontWeight: "700", cursor: "pointer", fontSize: "14px" },

  blob1: { position: "absolute", top: "5%", left: "5%", width: "250px", height: "250px", background: "#6366f1", filter: "blur(100px)", opacity: 0.1 },
  blob2: { position: "absolute", bottom: "5%", right: "5%", width: "250px", height: "250px", background: "#a855f7", filter: "blur(100px)", opacity: 0.1 },
};

export default App;
